```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Use sqlgen's insert function to add records
  // The table is determined by the type T, which should match the table structure
  auto insert_result = sqlgen::insert(conn, records);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Build delete statement using sqlgen's delete_from and where functionality
  // We need to determine the primary key column based on the table
  if (table_name == "Student" || table_name == "Major") {
    // These tables use SNo/MID as primary key (string type)
    auto delete_stmt = sqlgen::delete_from<sqlgen::TableWrapper<Student>>{} 
                      | sqlgen::where("SNo"_c == record_id);
    auto result = delete_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to delete record");
    }
  } else if (table_name == "Course" || table_name == "Score") {
    // These tables use CID/ScID as primary key (uint32_t type)
    // Convert record_id from string to uint32_t
    try {
      uint32_t id = static_cast<uint32_t>(std::stoull(record_id));
      auto delete_stmt = sqlgen::delete_from<sqlgen::TableWrapper<Course>>{} 
                        | sqlgen::where("CID"_c == id);
      auto result = delete_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to delete record");
      }
    } catch (std::exception& e) {
      throw std::runtime_error("Invalid record ID for numeric primary key");
    }
  } else {
    throw std::runtime_error("Unknown table name");
  }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::string& new_value) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Build update statement using sqlgen's update functionality
  // Determine the appropriate column type and value conversion
  if (table_name == "Student") {
    // Handle Student table specific columns
    if (col_name == "Sex") {
      // Sex is int type
      int sex_value;
      if (new_value == "1") sex_value = 1;
      else if (new_value == "0") sex_value = 0;
      else throw std::runtime_error("Invalid value for Sex column");

      auto update_stmt = sqlgen::update<Student>("Sex"_c.set(sex_value)) 
                        | sqlgen::where("SNo"_c == record_id);
      auto result = update_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to update record");
      }
    } else if (col_name == "Credit") {
      // Credit is int type
      int credit_value;
      try {
        credit_value = std::stoi(new_value);
      } catch (...) {
        throw std::runtime_error("Invalid value for Credit column");
      }

      auto update_stmt = sqlgen::update<Student>("Credit"_c.set(credit_value)) 
                        | sqlgen::where("SNo"_c == record_id);
      auto result = update_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to update record");
      }
    } else {
      // Other columns are string types
      auto update_stmt = sqlgen::update<Student>(col_name"_c.set(new_value)) 
                        | sqlgen::where("SNo"_c == record_id);
      auto result = update_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to update record");
      }
    }
  } else if (table_name == "Course") {
    // Handle Course table columns
    if (col_name == "Term") {
      int term_value;
      try {
        term_value = std::stoi(new_value);
      } catch (...) {
        throw std::runtime_error("Invalid value for Term column");
      }
      auto update_stmt = sqlgen::update<Course>("Term"_c.set(term_value)) 
                        | sqlgen::where("CID"_c == record_id);
      auto result = update_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to update record");
      }
    } else if (col_name == "CTime") {
      int ctime_value;
      try {
        ctime_value = std::stoi(new_value);
      } catch (...) {
        throw std::runtime_error("Invalid value for CTime column");
      }
      auto update_stmt = sqlgen::update<Course>("CTime"_c.set(ctime_value)) 
                        | sqlgen::where("CID"_c == record_id);
      auto result = update_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to update record");
      }
    } else {
      auto update_stmt = sqlgen::update<Course>(col_name"_c.set(new_value)) 
                        | sqlgen::where("CID"_c == record_id);
      auto result = update_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to update record");
      }
    }
  } else if (table_name == "Score") {
    // Handle Score table columns
    if (col_name == "Score") {
      double score_value;
      try {
        score_value = std::stod(new_value);
      } catch (...) {
        throw std::runtime_error("Invalid value for Score column");
      }
      auto update_stmt = sqlgen::update<Score>("Score"_c.set(score_value)) 
                        | sqlgen::where("ScID"_c == record_id);
      auto result = update_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to update record");
      }
    } else {
      auto update_stmt = sqlgen::update<Score>(col_name"_c.set(new_value)) 
                        | sqlgen::where("ScID"_c == record_id);
      auto result = update_stmt(conn);
      if (!result) {
        throw std::runtime_error("Failed to update record");
      }
    }
  } else if (table_name == "Major") {
    // Handle Major table columns
    auto update_stmt = sqlgen::update<Major>(col_name"_c.set(new_value)) 
                      | sqlgen::where("MID"_c == record_id);
    auto result = update_stmt(conn);
    if (!result) {
      throw std::runtime_error("Failed to update record");
    }
  } else {
    throw std::runtime_error("Unknown table name");
  }
}
