```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return 1; // Connection failed
  }
  auto conn = *conn_result;

  // Begin transaction
  auto trans_result = sqlgen::begin_transaction(conn);
  if (!trans_result) {
    return 1; // Transaction start failed
  }
  auto trans = *trans_result;

  // Delete users who haven't logged in since 2025-01-01
  auto delete_result = (sqlgen::delete_from<User> | 
                       sqlgen::where(&User::last_login < "2025-01-01"))(conn);
  if (!delete_result) {
    // Rollback on failure
    trans->rollback();
    return 1;
  }

  // Commit the transaction
  auto commit_result = sqlgen::commit(trans);
  if (!commit_result) {
    return 1; // Commit failed
  }

  return 0; // Success
}

} // namespace delete_inactive_users
```

