  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Start with base SELECT query from Book table
    auto query = sqlgen::select_from<Book>(
        sqlgen::col<Book>::book_id,
        sqlgen::col<Book>::title,
        sqlgen::col<Book>::author,
        sqlgen::col<Book>::year,
        sqlgen::col<Book>::genre,
        sqlgen::col<Book>::price
    );

    // Dynamically add WHERE clauses based on non-null input parameters
    if (filters.title_keyword.has_value()) {
        query = query | sqlgen::where(sqlgen::col<Book>::title.like("%" + filters.title_keyword.value() + "%"));
    }

    if (filters.min_year.has_value()) {
        query = query | sqlgen::where(sqlgen::col<Book>::year >= filters.min_year.value());
    }

    if (filters.genre.has_value()) {
        query = query | sqlgen::where(sqlgen::col<Book>::genre == filters.genre.value());
    }

    if (filters.max_price.has_value()) {
        query = query | sqlgen::where(sqlgen::col<Book>::price <= filters.max_price.value());
    }

    // Execute the query and return results
    return query(conn).value();
}

}  // namespace query_search_books_by_criteria
