  using namespace sqlgen::literals;

  // Connect to database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create tables (tables are automatically created by sqlgen when writing data)

  // Query 1: Mutual Friends using SELF-JOIN
  auto mutual_friends_query = 
    sqlgen::select_from<User, "u1">("username"_t1.as<"user1_name">(), 
                                   "username"_t2.as<"user2_name">(),
                                   sqlgen::count("user_id2"_t1).as<"mutual_count">())
    | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
    | sqlgen::inner_join<Friendship, "f2">("user_id2"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<User, "u2">("user_id2"_t2 == "user_id"_t2)
    | sqlgen::where("user_id"_t1 < "user_id"_t2)
    | sqlgen::group_by("user_id"_t1, "user_id"_t2)
    | sqlgen::having(sqlgen::count("user_id2"_t1) > 0);

  // Query 2: Users with more than N friends using nested query
  auto avg_friends_query = sqlgen::select_from<User, "u">(
      "username"_t1,
      sqlgen::count("user_id2"_t1).as<"friend_count">())
    | sqlgen::left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t1)
    | sqlgen::group_by("user_id"_t1);

