                     | sqlgen::left_join<Friendship, "f2">("user_id"_t2 == "user_id1"_t2)
                     | sqlgen::group_by("user_id"_t2)
                     | sqlgen::avg("friend_count"))))
    | sqlgen::group_by("user_id"_t1);

  // Query 3: Friend-of-Friend relationships
