bool update_set_operations() {
  try {
    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result.is_ok()) {
      return false;
    }
    auto conn = conn_result.value();

    // 2. Create Account table
    const char* create_table_sql = R"(
      CREATE TABLE Account (
        account_id INTEGER PRIMARY KEY,
        balance REAL NOT NULL,
        status TEXT NOT NULL
      )
    )";

    auto create_result = conn->execute(create_table_sql);
    if (!create_result.is_ok()) {
      return false;
    }

    // 3. Insert initial data for testing
    Account initial_account{1, 1000.0, "active"};
    auto insert_result = sqlgen::write(conn, initial_account);
    if (!insert_result.is_ok()) {
      return false;
