JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create tables and insert data
  auto write_dept_result = sqlgen::write(conn, depts);
  if (!write_dept_result) {
    throw std::runtime_error("Failed to write department data");
  }

  auto write_emp_result = sqlgen::write(conn, emps);
  if (!write_emp_result) {
    throw std::runtime_error("Failed to write employee data");
  }

  // Define column references using table aliases
  auto dept_id_col = "department_id"_t1;
  auto emp_id_col = "department_id"_t2;
  auto dept_name_col = "department_name"_t1;
  auto first_name_col = "first_name"_t2;
  auto last_name_col = "last_name"_t2;
  auto salary_col = "salary"_t2;

  // Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(dept_name_col, first_name_col, last_name_col, salary_col)
      .inner_join<Employee, "e">(dept_id_col == emp_id_col)
      .to<std::vector<JoinResult>>();

  auto inner_result = inner_query(conn);
  if (!inner_result) {
    throw std::runtime_error("Failed to execute INNER JOIN query");
  }
  auto inner_joins = inner_result.value();

  // Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(dept_name_col, first_name_col, last_name_col, salary_col)
      .left_join<Department, "d">(emp_id_col == dept_id_col)
      .to<std::vector<JoinResult>>();

  auto left_result = left_query(conn);
  if (!left_result) {
    throw std::runtime_error("Failed to execute LEFT JOIN query");
  }
  auto left_joins = left_result.value();

  // Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Employee, "e">(dept_name_col, first_name_col, last_name_col, salary_col)
      .right_join<Department, "d">(emp_id_col == dept_id_col)
      .to<std::vector<JoinResult>>();

  auto right_result = right_query(conn);
  if (!right_result) {
    throw std::runtime_error("Failed to execute RIGHT JOIN query");
  }
  auto right_joins = right_result.value();

  // Perform FULL JOIN
  auto full_query = sqlgen::select_from<Department, "d">(dept_name_col, first_name_col, last_name_col, salary_col)
      .full_join<Employee, "e">(dept_id_col == emp_id_col)
      .to<std::vector<JoinResult>>();

  auto full_result = full_query(conn);
  if (!full_result) {
    throw std::runtime_error("Failed to execute FULL JOIN query");
  }
  auto full_joins = full_result.value();

  // Return comprehensive analysis
  return JoinAnalysis{
      .inner_join_results = std::move(inner_joins),
      .left_join_results = std::move(left_joins),
      .right_join_results = std::move(right_joins),
      .full_join_results = std::move(full_joins)
  };
}

}  // namespace analyze_department_employees
